// Parsing separated (SRP)
record Order(String id, String email, double unitPrice, int quantity) {}

class OrderParser {
    Order parse(String csvLine) {
        String[] p = csvLine.split(",");
        if (p.length != 4) throw new IllegalArgumentException("Malformed order line");
        return new Order(p[0], p[1], Double.parseDouble(p[2]), Integer.parseInt(p[3]));
    }
}

// Pricing as a strategy (OCP): add rules without editing OrderService
interface PricingRule { double apply(double subtotal); }

class BulkDiscountRule implements PricingRule {
    public double apply(double subtotal) {
        return subtotal > 100 ? subtotal * 0.9 : subtotal;
    }
}

class PricingService {
    private final List<PricingRule> rules;
    PricingService(List<PricingRule> rules) { this.rules = rules; }
    double total(Order o) {
        double t = o.unitPrice() * o.quantity();
        for (PricingRule r : rules) t = r.apply(t);
        return t;
    }
}

// Abstractions for persistence and notification (DIP)
interface OrderRepository { void save(String id, double total); }
interface Notifier { void notifyConfirmed(String email, double total); }

class JdbcOrderRepository implements OrderRepository {
    private final DataSource ds;
    JdbcOrderRepository(DataSource ds) { this.ds = ds; }
    public void save(String id, double total) {
        try (Connection c = ds.getConnection();
             PreparedStatement ps = c.prepareStatement(
                 "INSERT INTO orders (id, total) VALUES (?, ?)")) {
            ps.setString(1, id);
            ps.setBigDecimal(2, java.math.BigDecimal.valueOf(total));
            ps.executeUpdate();
        } catch (SQLException e) {
            throw new PersistenceException("Failed to save order " + id, e);
        }
    }
}

class OrderService {
    private final OrderParser parser;
    private final PricingService pricing;
    private final OrderRepository repository;
    private final Notifier notifier;

    OrderService(OrderParser parser, PricingService pricing,
                 OrderRepository repository, Notifier notifier) {
        this.parser = parser;
        this.pricing = pricing;
        this.repository = repository;
        this.notifier = notifier;
    }

    void process(String csvLine) {
        Order order = parser.parse(csvLine);
        double total = pricing.total(order);
        repository.save(order.id(), total);
        notifier.notifyConfirmed(order.email(), total);
    }
}

