// );

@RestController
@RequestMapping("/api/tasks")
class TaskController {
    private final TaskRepository repo;
    TaskController(TaskRepository repo) { this.repo = repo; }

    @GetMapping
    List<Task> list() { return repo.findAllByOrderByCreatedAtDesc(); }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    Task create(@Valid @RequestBody CreateTaskRequest req) {
        return repo.save(new Task(req.title()));
    }

    @PostMapping("/{id}/complete")
    Task complete(@PathVariable UUID id) {
        Task t = repo.findById(id)
            .orElseThrow(() -> new NotFoundException("Task not found: " + id));
        t.markDone();
        return repo.save(t);
    }
}

record CreateTaskRequest(@NotBlank @Size(max = 200) String title) {}

@RestControllerAdvice
class ApiExceptionHandler {
    @ExceptionHandler(NotFoundException.class)
    @ResponseStatus(HttpStatus.NOT_FOUND)
    ApiError notFound(NotFoundException e) {
        return new ApiError("NOT_FOUND", e.getMessage());
    }
    @ExceptionHandler(MethodArgumentNotValidException.class)
    @ResponseStatus(HttpStatus.BAD_REQUEST)
    ApiError invalid(MethodArgumentNotValidException e) {
        return new ApiError("VALIDATION", e.getMessage());
    }
}
record ApiError(String code, String message) {}

// --- Frontend sketch (React) ---
function TaskList() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const load = async () => {
    setLoading(true); setError(null);
    try {
      const res = await fetch('/api/tasks');
      if (!res.ok) throw new Error('Failed to load tasks');
      setTasks(await res.json());
    } catch (e) {
      setError((e as Error).message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  if (loading) return <Spinner />;
  if (error) return <ErrorBanner message={error} onRetry={load} />;
  return (
    <ul>
      {tasks.map(t => (
        <li key={t.id}>
          {t.title} - {t.status}
          {t.status === 'OPEN' && (
            <button onClick={() => complete(t.id).then(load)}>Complete</button>
          )}
        </li>
      ))}
    </ul>
  );
}
